import numpy as np
import matplotlib.pyplot as plt

# Newton's method to find sqrt(9)
# f(x) = x^2 - 9, f'(x) = 2x
# x_{n+1} = x_n - f(x_n)/f'(x_n) = x_n - (x_n^2 - 9)/(2*x_n) = (x_n + 9/x_n) / 2

target = 9
true_sqrt = np.sqrt(target)

# Starting guess
x0 = 1.0
iterations = []
x = x0
max_iter = 10

for i in range(max_iter):
    iterations.append(x)
    x_new = (x + target / x) / 2.0
    if abs(x_new - x) < 1e-12:
        x = x_new
        iterations.append(x)
        break
    x = x_new

iterations = np.array(iterations)
errors = np.abs(iterations - true_sqrt)
iter_nums = np.arange(len(iterations))

# --- Plotting ---
fig, axes = plt.subplots(1, 3, figsize=(15, 5))
plt.suptitle("Newton's Method: Square Root of 9", y=0.98)

# --- Plot 1: Approximation vs Iteration ---
ax1 = axes[0]
ax1.plot(iter_nums, iterations, 'bo-', linewidth=2, markersize=8, label='Approximation')
ax1.axhline(y=true_sqrt, color='r', linestyle='--', linewidth=2, label=f'True sqrt(9) = {true_sqrt}')
ax1.set_title("Approximation per Iteration")
ax1.set_xlabel("Iteration")
ax1.set_ylabel("x_n")
ax1.legend()
ax1.grid(True, alpha=0.3)
ax1.set_xticks(iter_nums)

# --- Plot 2: Error vs Iteration (log scale) ---
ax2 = axes[1]
# Avoid log(0) by filtering
nonzero_mask = errors > 0
ax2.semilogy(iter_nums[nonzero_mask], errors[nonzero_mask], 'rs-', linewidth=2, markersize=8, label='|x_n - sqrt(9)|')
ax2.set_title("Error per Iteration (Log Scale)")
ax2.set_xlabel("Iteration")
ax2.set_ylabel("Absolute Error")
ax2.legend()
ax2.grid(True, which='both', alpha=0.3)
ax2.set_xticks(iter_nums[nonzero_mask])

# --- Plot 3: Geometric view of Newton's method ---
ax3 = axes[2]
x_vals = np.linspace(0.5, 5.5, 400)
y_vals = x_vals**2 - target

ax3.plot(x_vals, y_vals, 'b-', linewidth=2, label='f(x) = x^2 - 9')
ax3.axhline(0, color='k', linewidth=1)
ax3.axvline(true_sqrt, color='r', linestyle='--', linewidth=1.5, label=f'Root x = {true_sqrt}')

colors = plt.cm.viridis(np.linspace(0, 0.85, min(5, len(iterations))))
for i in range(min(5, len(iterations) - 1)):
    xi = iterations[i]
    fi = xi**2 - target
    dfi = 2 * xi
    # Tangent line: y - fi = dfi*(x - xi)
    x_tan = np.linspace(xi - 1.5, xi + 1.5, 100)
    y_tan = fi + dfi * (x_tan - xi)
    ax3.plot(x_tan, y_tan, '--', color=colors[i], alpha=0.8, linewidth=1.2)
    ax3.plot(xi, fi, 'o', color=colors[i], markersize=8)
    ax3.annotate(f'x_{i}={xi:.3f}', xy=(xi, fi), xytext=(xi + 0.1, fi + 1.5),
                 fontsize=7, color=colors[i])

ax3.set_ylim(-10, 20)
ax3.set_xlim(0.5, 5.5)
ax3.set_title("Geometric View of Newton's Method")
ax3.set_xlabel("x")
ax3.set_ylabel("f(x)")
ax3.legend(fontsize=8)
ax3.grid(True, alpha=0.3)

plt.tight_layout()
plt.savefig("newtons_method_sqrt9.png", dpi=120, bbox_inches='tight')
plt.show()

# Print results
print("Newton's Method - Finding sqrt(9)")
